import main.Card;
import main.CopasGameState;
import main.Deck;

import java.lang.reflect.Field;
import java.util.ArrayList;
import java.util.List;

public class CopasRulesSmoke {
    public static void main(String[] args) throws Exception {
        invalidPlay();
        drawTwo();
        goldenOne();
        suitChange();
    }

    private static void invalidPlay() throws Exception {
        CopasGameState state = new CopasGameState();
        setField(state, "drawPile", new Deck(new ArrayList<>(List.of(new Card("Basto", 9)))));
        List<Card> discardPile = getField(state, "discardPile");
        discardPile.clear();
        discardPile.add(new Card("Copa", 5));
        setField(state, "activeSuit", "Copa");

        List<List<Card>> hands = getField(state, "playerHands");
        hands.clear();
        hands.add(new ArrayList<>(List.of(new Card("Oro", 7))));
        hands.add(new ArrayList<>(List.of(new Card("Copa", 6))));
        hands.add(new ArrayList<>(List.of(new Card("Basto", 1))));
        hands.add(new ArrayList<>(List.of(new Card("Espada", 3))));

        System.out.println("invalidPlayed=" + state.playHumanCard(0, null) + ", top=" + state.getTopCard().getDisplayName());
    }

    private static void drawTwo() throws Exception {
        CopasGameState state = new CopasGameState();
        setField(state, "drawPile", new Deck(new ArrayList<>(List.of(
                new Card("Copa", 4),
                new Card("Espada", 6),
                new Card("Basto", 9)
        ))));
        List<Card> discardPile = getField(state, "discardPile");
        discardPile.clear();
        discardPile.add(new Card("Copa", 2));
        setField(state, "activeSuit", "Copa");

        List<List<Card>> hands = getField(state, "playerHands");
        hands.clear();
        hands.add(new ArrayList<>(List.of(new Card("Oro", 2), new Card("Basto", 8))));
        hands.add(new ArrayList<>(List.of(new Card("Basto", 3))));
        hands.add(new ArrayList<>(List.of(new Card("Espada", 4))));
        hands.add(new ArrayList<>(List.of(new Card("Oro", 5))));

        System.out.println("drawTwoPlayed=" + state.playHumanCard(0, null)
                + ", ai1Count=" + state.getPlayerCardCount(1)
                + ", currentPlayer=" + state.getPlayerName(state.getCurrentPlayerIndex())
                + ", top=" + state.getTopCard().getDisplayName());
    }

    private static void goldenOne() throws Exception {
        CopasGameState state = new CopasGameState();
        setField(state, "drawPile", new Deck(new ArrayList<>(List.of(
                new Card("Basto", 4),
                new Card("Basto", 5),
                new Card("Basto", 6),
                new Card("Basto", 7),
                new Card("Basto", 8),
                new Card("Basto", 9)
        ))));
        List<Card> discardPile = getField(state, "discardPile");
        discardPile.clear();
        discardPile.add(new Card("Oro", 3));
        setField(state, "activeSuit", "Oro");

        List<List<Card>> hands = getField(state, "playerHands");
        hands.clear();
        hands.add(new ArrayList<>(List.of(new Card("Oro", 1), new Card("Copa", 8))));
        hands.add(new ArrayList<>(List.of(new Card("Copa", 6))));
        hands.add(new ArrayList<>(List.of(new Card("Espada", 4))));
        hands.add(new ArrayList<>(List.of(new Card("Oro", 5))));

        System.out.println("goldenOnePlayed=" + state.playHumanCard(0, null)
                + ", ai1Count=" + state.getPlayerCardCount(1)
                + ", currentPlayer=" + state.getPlayerName(state.getCurrentPlayerIndex())
                + ", top=" + state.getTopCard().getDisplayName());
    }

    private static void suitChange() throws Exception {
        CopasGameState state = new CopasGameState();
        setField(state, "drawPile", new Deck(new ArrayList<>(List.of(new Card("Copa", 9)))));
        List<Card> discardPile = getField(state, "discardPile");
        discardPile.clear();
        discardPile.add(new Card("Basto", 7));
        setField(state, "activeSuit", "Basto");

        List<List<Card>> hands = getField(state, "playerHands");
        hands.clear();
        hands.add(new ArrayList<>(List.of(new Card("Basto", 7), new Card("Oro", 3))));
        hands.add(new ArrayList<>(List.of(new Card("Copa", 6))));
        hands.add(new ArrayList<>(List.of(new Card("Espada", 4))));
        hands.add(new ArrayList<>(List.of(new Card("Oro", 5))));

        System.out.println("suitChangePlayed=" + state.playHumanCard(0, "Espada")
                + ", activeSuit=" + state.getActiveSuit()
                + ", top=" + state.getTopCard().getDisplayName());
    }

    @SuppressWarnings("unchecked")
    private static <T> T getField(Object target, String name) throws Exception {
        Field field = target.getClass().getDeclaredField(name);
        field.setAccessible(true);
        return (T) field.get(target);
    }

    private static void setField(Object target, String name, Object value) throws Exception {
        Field field = target.getClass().getDeclaredField(name);
        field.setAccessible(true);
        field.set(target, value);
    }
}

package main;

import javax.imageio.ImageIO;
import java.awt.Graphics2D;
import java.awt.image.BufferedImage;
import java.io.IOException;
import java.io.InputStream;
import java.util.HashMap;
import java.util.Map;
import java.util.Objects;

public class Card {
    private static final Map<String, BufferedImage> FRONT_IMAGE_CACHE = new HashMap<>();
    private static final BufferedImage BACK_IMAGE = loadImage("cards/cardBack.png");

    private final String type;
    private final int number;
    private final BufferedImage frontView;

    public Card(String type, int number) {
        this.type = type;
        this.number = number;
        this.frontView = FRONT_IMAGE_CACHE.computeIfAbsent(buildFrontImagePath(type, number), Card::loadImage);
    }

    public String getType() {
        return type;
    }

    public int getNumber() {
        return number;
    }

    public void drawFront(Graphics2D g2, int x, int y, int width, int height) {
        g2.drawImage(frontView, x, y, width, height, null);
    }

    public void drawBack(Graphics2D g2, int x, int y, int width, int height) {
        drawBackImage(g2, x, y, width, height);
    }

    public static void drawBackImage(Graphics2D g2, int x, int y, int width, int height) {
        g2.drawImage(BACK_IMAGE, x, y, width, height, null);
    }

    private static String buildFrontImagePath(String type, int number) {
        String normalizedType = Objects.requireNonNull(type, "Card type cannot be null").trim();

        return switch (normalizedType) {
            case "Basto" -> "cards/Basto/basto" + number + ".png";
            case "Copa" -> "cards/Copa/copa" + number + ".png";
            case "Espada" -> "cards/Espada/espada" + number + ".png";
            case "Oro" -> "cards/Oro/oro" + number + ".png";
            default -> throw new IllegalArgumentException("Unknown card type: " + type);
        };
    }

    private static BufferedImage loadImage(String resourcePath) {
        try (InputStream inputStream = Card.class.getClassLoader().getResourceAsStream(resourcePath)) {
            if (inputStream == null) {
                throw new IllegalStateException("Missing resource: " + resourcePath);
            }

            return ImageIO.read(inputStream);
        } catch (IOException e) {
            throw new IllegalStateException("Failed to load resource: " + resourcePath, e);
        }
    }

}

package main;

import javax.imageio.ImageIO;
import java.awt.Graphics2D;
import java.awt.image.BufferedImage;
import java.io.IOException;
import java.io.InputStream;
import java.util.HashMap;
import java.util.Map;
import java.util.Objects;

public class Card {
    private static final Map<String, BufferedImage> FRONT_IMAGE_CACHE = new HashMap<>();
    private static final BufferedImage BACK_IMAGE = loadImage("cards/cardBack.png");

    private final String type;
    private final int number;
    private final BufferedImage frontView;

    public Card(String type, int number) {
        this.type = type;
        this.number = number;
        this.frontView = FRONT_IMAGE_CACHE.computeIfAbsent(buildFrontImagePath(type, number), Card::loadImage);
    }

    public String getType() {
        return type;
    }

    public int getNumber() {
        return number;
    }

    public boolean matches(Card topCard, String activeSuit) {
        return number == topCard.number || type.equals(activeSuit);
    }

    public boolean isDrawTwo() {
        return number == 2;
    }

    public boolean isSkip() {
        return number == 1 && !isGoldenOne();
    }

    public boolean isSuitChange() {
        return number == 7;
    }

    public boolean isGoldenOne() {
        return number == 1 && "Oro".equals(type);
    }

    public boolean isSpecialCard() {
        return isDrawTwo() || isSkip() || isSuitChange() || isGoldenOne();
    }

    public String getDisplayName() {
        return type + " " + number;
    }

    public void drawFront(Graphics2D g2, int x, int y, int width, int height) {
        g2.drawImage(frontView, x, y, width, height, null);
    }

    public void drawBack(Graphics2D g2, int x, int y, int width, int height) {
        drawBackImage(g2, x, y, width, height);
    }

    public static void drawBackImage(Graphics2D g2, int x, int y, int width, int height) {
        g2.drawImage(BACK_IMAGE, x, y, width, height, null);
    }

    private static String buildFrontImagePath(String type, int number) {
        String normalizedType = Objects.requireNonNull(type, "Card type cannot be null").trim();

        return switch (normalizedType) {
            case "Basto" -> "cards/Basto/basto" + number + ".png";
            case "Copa" -> "cards/Copa/copa" + number + ".png";
            case "Espada" -> "cards/Espada/espada" + number + ".png";
            case "Oro" -> "cards/Oro/oro" + number + ".png";
            default -> throw new IllegalArgumentException("Unknown card type: " + type);
        };
    }

    private static BufferedImage loadImage(String resourcePath) {
        try (InputStream inputStream = Card.class.getClassLoader().getResourceAsStream(resourcePath)) {
            if (inputStream == null) {
                throw new IllegalStateException("Missing resource: " + resourcePath);
            }

            return ImageIO.read(inputStream);
        } catch (IOException e) {
            throw new IllegalStateException("Failed to load resource: " + resourcePath, e);
        }
    }

}

package main;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

public class CopasGameState {
    public static final int HUMAN_PLAYER_INDEX = 0;
    private static final int PLAYER_COUNT = 4;
    private static final int STARTING_HAND_SIZE = 4;
    private static final String[] PLAYER_NAMES = {"You", "AI 1", "AI 2", "AI 3"};
    private static final String[] SUITS = {"Basto", "Copa", "Espada", "Oro"};

    private Deck drawPile;
    private final List<Card> discardPile = new ArrayList<>();
    private final List<List<Card>> playerHands = new ArrayList<>();
    private final boolean[] finishedPlayers = new boolean[PLAYER_COUNT];

    private int currentPlayerIndex = HUMAN_PLAYER_INDEX;
    private String activeSuit;
    private String statusMessage = "Your turn. Play a matching card or draw from the pile.";
    private boolean roundOver;
    private boolean humanHasDrawnThisTurn;

    public CopasGameState() {
        startRound();
    }

    public void startRound() {
        drawPile = Deck.createShuffledSpanishDeck();
        discardPile.clear();
        playerHands.clear();
        roundOver = false;
        humanHasDrawnThisTurn = false;
        currentPlayerIndex = HUMAN_PLAYER_INDEX;

        for (int playerIndex = 0; playerIndex < PLAYER_COUNT; playerIndex++) {
            finishedPlayers[playerIndex] = false;
            playerHands.add(drawPile.dealCards(STARTING_HAND_SIZE));
        }

        Card openingCard = drawFromPile();
        if (openingCard == null) {
            throw new IllegalStateException("Unable to start the round because no opening card could be drawn.");
        }

        discardPile.add(openingCard);
        activeSuit = openingCard.getType();
        statusMessage = "Your turn. Top card: " + openingCard.getDisplayName() + ". Active suit: " + activeSuit + ".";
    }

    public List<Card> getHumanHand() {
        return List.copyOf(playerHands.get(HUMAN_PLAYER_INDEX));
    }

    public Card getTopCard() {
        return discardPile.getLast();
    }

    public String getActiveSuit() {
        return activeSuit;
    }

    public String getStatusMessage() {
        return statusMessage;
    }

    public int getDrawPileSize() {
        return drawPile.size();
    }

    public boolean isHumanTurn() {
        return !roundOver && currentPlayerIndex == HUMAN_PLAYER_INDEX && !finishedPlayers[HUMAN_PLAYER_INDEX];
    }

    public boolean isHumanCardPlayable(int handIndex) {
        List<Card> humanHand = playerHands.get(HUMAN_PLAYER_INDEX);
        if (handIndex < 0 || handIndex >= humanHand.size()) {
            return false;
        }

        return canPlay(humanHand.get(handIndex));
    }

    public boolean canHumanDraw() {
        return isHumanTurn() && !humanHasDrawnThisTurn && !hasPlayableCard() && canDrawFromPile();
    }

    public boolean isRoundOver() {
        return roundOver;
    }

    public boolean hasAvailableDrawPile() {
        return canDrawFromPile();
    }

    public int getCurrentPlayerIndex() {
        return currentPlayerIndex;
    }

    public int getPlayerCardCount(int playerIndex) {
        return playerHands.get(playerIndex).size();
    }

    public String getPlayerName(int playerIndex) {
        return PLAYER_NAMES[playerIndex];
    }

    public boolean isPlayerFinished(int playerIndex) {
        return finishedPlayers[playerIndex];
    }

    public boolean playHumanCard(int handIndex, String chosenSuit) {
        if (!isHumanTurn()) {
            statusMessage = roundOver ? statusMessage : "Wait for your turn.";
            return false;
        }

        List<Card> humanHand = playerHands.get(HUMAN_PLAYER_INDEX);
        if (handIndex < 0 || handIndex >= humanHand.size()) {
            statusMessage = "That card is no longer available.";
            return false;
        }

        Card card = humanHand.get(handIndex);
        if (!canPlay(card)) {
            statusMessage = "You can only play a card with the same number or the active suit (" + activeSuit + ").";
            return false;
        }

        playCard(HUMAN_PLAYER_INDEX, handIndex, normalizeChosenSuit(card, chosenSuit));
        if (!roundOver) {
            runAiTurns();
        }
        return true;
    }

    public void drawForHuman() {
        if (!isHumanTurn()) {
            statusMessage = roundOver ? statusMessage : "Wait for your turn before drawing.";
            return;
        }
        if (humanHasDrawnThisTurn) {
            statusMessage = "You already drew this turn. Play a valid card if you can.";
            return;
        }
        if (hasPlayableCard()) {
            statusMessage = "You already have a playable card. Play it instead of drawing.";
            return;
        }

        Card drawnCard = drawFromPile();
        if (drawnCard == null) {
            statusMessage = "No cards left to draw.";
            return;
        }

        playerHands.get(HUMAN_PLAYER_INDEX).add(drawnCard);
        humanHasDrawnThisTurn = true;

        if (canPlay(drawnCard)) {
            statusMessage = "You drew " + drawnCard.getDisplayName() + ". You may play it or another valid card.";
        } else {
            statusMessage = "You drew " + drawnCard.getDisplayName() + " and it cannot be played. Turn passes.";
            endTurnAfterAction(drawnCard.getDisplayName() + " was not playable.");
            if (!roundOver) {
                runAiTurns();
            }
        }
    }

    private void runAiTurns() {
        while (!roundOver && currentPlayerIndex != HUMAN_PLAYER_INDEX) {
            int aiIndex = currentPlayerIndex;
            if (finishedPlayers[aiIndex]) {
                currentPlayerIndex = getNextActivePlayer(aiIndex);
                continue;
            }

            takeAiTurn(aiIndex);
        }

        if (!roundOver) {
            humanHasDrawnThisTurn = false;
            if (!hasPlayableCard()) {
                statusMessage = statusMessage + " Your turn: no playable card, draw from the pile.";
            } else if (!statusMessage.contains("Your turn")) {
                statusMessage = statusMessage + " Your turn.";
            }
        }
    }

    private void takeAiTurn(int aiIndex) {
        List<Card> aiHand = playerHands.get(aiIndex);
        int playableIndex = findPlayableCardIndex(aiHand);

        if (playableIndex >= 0) {
            Card card = aiHand.get(playableIndex);
            String chosenSuit = card.isSuitChange() ? chooseSuitForAi(aiHand, playableIndex) : null;
            playCard(aiIndex, playableIndex, chosenSuit);
            return;
        }

        Card drawnCard = drawFromPile();
        if (drawnCard == null) {
            statusMessage = getPlayerName(aiIndex) + " could not draw. ";
            currentPlayerIndex = getNextActivePlayer(aiIndex);
            return;
        }

        aiHand.add(drawnCard);
        if (canPlay(drawnCard)) {
            String chosenSuit = drawnCard.isSuitChange() ? chooseSuitForAi(aiHand, aiHand.size() - 1) : null;
            playCard(aiIndex, aiHand.size() - 1, chosenSuit);
        } else {
            statusMessage = getPlayerName(aiIndex) + " drew a card and passed.";
            currentPlayerIndex = getNextActivePlayer(aiIndex);
        }
    }

    private void playCard(int playerIndex, int handIndex, String chosenSuit) {
        List<Card> hand = playerHands.get(playerIndex);
        Card card = hand.remove(handIndex);
        discardPile.add(card);
        activeSuit = card.isSuitChange() ? chosenSuit : card.getType();

        StringBuilder actionMessage = new StringBuilder();
        actionMessage.append(getPlayerName(playerIndex))
                .append(" played ")
                .append(card.getDisplayName());

        if (card.isSuitChange()) {
            actionMessage.append(" and changed the suit to ").append(activeSuit);
        }

        if (hand.isEmpty()) {
            markPlayerFinished(playerIndex, actionMessage);
        }

        applyCardEffect(playerIndex, card, actionMessage);

        if (!roundOver) {
            statusMessage = actionMessage.append('.').toString();
        }
    }

    private void applyCardEffect(int playerIndex, Card card, StringBuilder actionMessage) {
        if (remainingPlayers() <= 1) {
            finishRound();
            return;
        }

        if (card.isGoldenOne()) {
            int targetPlayer = getNextActivePlayer(playerIndex);
            int drawn = drawCardsForPlayer(targetPlayer, 5);
            actionMessage.append(". ").append(getPlayerName(targetPlayer)).append(" draws ").append(drawn).append(" cards and is skipped");
            currentPlayerIndex = getNextActivePlayer(targetPlayer);
            return;
        }

        if (card.isDrawTwo()) {
            int targetPlayer = getNextActivePlayer(playerIndex);
            int drawn = drawCardsForPlayer(targetPlayer, 2);
            actionMessage.append(". ").append(getPlayerName(targetPlayer)).append(" draws ").append(drawn).append(" cards and is skipped");
            currentPlayerIndex = getNextActivePlayer(targetPlayer);
            return;
        }

        if (card.isSkip()) {
            int skippedPlayer = getNextActivePlayer(playerIndex);
            actionMessage.append(". ").append(getPlayerName(skippedPlayer)).append(" is skipped");
            currentPlayerIndex = getNextActivePlayer(skippedPlayer);
            return;
        }

        currentPlayerIndex = getNextActivePlayer(playerIndex);
    }

    private void endTurnAfterAction(String detail) {
        currentPlayerIndex = getNextActivePlayer(HUMAN_PLAYER_INDEX);
        statusMessage = detail;
    }

    private void markPlayerFinished(int playerIndex, StringBuilder actionMessage) {
        if (finishedPlayers[playerIndex]) {
            return;
        }

        finishedPlayers[playerIndex] = true;
        actionMessage.append(" and finished their cards");
    }

    private void finishRound() {
        roundOver = true;
        int loserIndex = -1;

        for (int playerIndex = 0; playerIndex < PLAYER_COUNT; playerIndex++) {
            if (!finishedPlayers[playerIndex]) {
                loserIndex = playerIndex;
                break;
            }
        }

        if (loserIndex == HUMAN_PLAYER_INDEX) {
            statusMessage = "Round over. You are the last player with cards and lose this round.";
        } else if (loserIndex >= 0) {
            statusMessage = "Round over. " + getPlayerName(loserIndex) + " is the last player with cards and loses this round.";
        } else {
            statusMessage = "Round over.";
        }
    }

    private int drawCardsForPlayer(int playerIndex, int count) {
        int drawnCards = 0;

        for (int i = 0; i < count; i++) {
            Card card = drawFromPile();
            if (card == null) {
                break;
            }
            playerHands.get(playerIndex).add(card);
            drawnCards++;
        }

        return drawnCards;
    }

    private Card drawFromPile() {
        replenishDrawPileIfNeeded();
        if (drawPile.isEmpty()) {
            return null;
        }

        return drawPile.drawCard();
    }

    private boolean canDrawFromPile() {
        return !drawPile.isEmpty() || discardPile.size() > 1;
    }

    private void replenishDrawPileIfNeeded() {
        if (!drawPile.isEmpty() || discardPile.size() <= 1) {
            return;
        }

        Card topCard = discardPile.removeLast();
        List<Card> recycledCards = new ArrayList<>(discardPile);
        discardPile.clear();
        discardPile.add(topCard);

        drawPile = new Deck(recycledCards);
        drawPile.shuffle();
    }

    private boolean canPlay(Card card) {
        return card.matches(getTopCard(), activeSuit);
    }

    private boolean hasPlayableCard() {
        return playerHands.get(HUMAN_PLAYER_INDEX).stream().anyMatch(this::canPlay);
    }

    private int findPlayableCardIndex(List<Card> hand) {
        for (int cardIndex = 0; cardIndex < hand.size(); cardIndex++) {
            if (canPlay(hand.get(cardIndex))) {
                return cardIndex;
            }
        }
        return -1;
    }

    private int getNextActivePlayer(int fromPlayerIndex) {
        int nextPlayerIndex = fromPlayerIndex;
        do {
            nextPlayerIndex = (nextPlayerIndex + 1) % PLAYER_COUNT;
        } while (finishedPlayers[nextPlayerIndex]);
        return nextPlayerIndex;
    }

    private int remainingPlayers() {
        int count = 0;
        for (boolean finished : finishedPlayers) {
            if (!finished) {
                count++;
            }
        }
        return count;
    }

    private String chooseSuitForAi(List<Card> hand, int playedCardIndex) {
        List<Card> remainingCards = new ArrayList<>(hand);
        remainingCards.remove(playedCardIndex);

        return remainingCards.stream()
                .filter(card -> !card.isSuitChange())
                .collect(java.util.stream.Collectors.groupingBy(Card::getType, java.util.stream.Collectors.counting()))
                .entrySet()
                .stream()
                .max(Comparator.comparingLong(java.util.Map.Entry::getValue))
                .map(java.util.Map.Entry::getKey)
                .orElse(SUITS[0]);
    }

    private String normalizeChosenSuit(Card card, String chosenSuit) {
        if (!card.isSuitChange()) {
            return card.getType();
        }

        for (String suit : SUITS) {
            if (suit.equals(chosenSuit)) {
                return suit;
            }
        }

        return card.getType();
    }
}

package main;

import javax.swing.*;
import java.awt.*;
import java.util.List;

public class GamePanel extends JPanel implements Runnable {
    //    Screen settings
    final int originalTilesSize = 64; // 16x16 tile
    final int scale = 2;

    public int tileSize = originalTilesSize * scale; // 48x48 tile
    final int maxScreenCol = 16;
    final int maxScreenRow = 12;
    final int screenWidth = (tileSize * maxScreenCol) / 2; // 768 pixels
    final int screenHeight = (tileSize * maxScreenRow) / 2; // 576 pixels

    //    Game's frame rate
    int FPS = 60;

    Thread gameThread;
    private static final int PLAYER_HAND_SIZE = 4;
    private static final int TABLE_MARGIN = 24;
    private static final int STACK_OFFSET = 4;
    private static final int MAX_VISIBLE_STACK = 6;
    private static final double HAND_FAN_SPREAD_DEGREES = 36.0;
    private final int cardWidth = tileSize - 24;
    private final int cardHeight = (int) Math.round(cardWidth * 1.45);

    private Deck drawPile;
    private Card centerCard;
    private List<Card> playerHand;

    public GamePanel() {
        this.setPreferredSize(new Dimension(screenWidth, screenHeight));
        this.setBackground(new Color(16, 94, 58));
        this.setDoubleBuffered(true);
        this.initializeTable();
    }

    private void initializeTable() {
        drawPile = Deck.createShuffledSpanishDeck();
        centerCard = drawPile.drawCard();
        playerHand = drawPile.dealCards(PLAYER_HAND_SIZE);
    }

    public void startGameThread() {
        gameThread = new Thread(this);
        gameThread.start();
    }

    public void run() {
        double drawInterval = 1000000000.0 / FPS;
        double delta = 0;
        long lastTime = System.nanoTime();
        long currentTime;

        while (gameThread != null) {
            currentTime = System.nanoTime();

            delta += (currentTime - lastTime) / drawInterval;
            lastTime = currentTime;

            if (delta >= 1) {
                update();
                repaint();
                delta--;
            }

        }
    }

    //    Methode to update the frame
    public void update() {
        // Table is static for now.
    }

    //    Methode to draw
    public void paintComponent(Graphics g) {
        super.paintComponent(g);
        Graphics2D g2 = (Graphics2D) g;
        g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g2.setRenderingHint(RenderingHints.KEY_RENDERING, RenderingHints.VALUE_RENDER_QUALITY);

        drawCenterCard(g2);
        drawPlayerHand(g2);
        drawDrawPile(g2);

        g2.dispose();
    }

    private void drawCenterCard(Graphics2D g2) {
        if (centerCard == null) {
            return;
        }

        int x = (screenWidth - cardWidth) / 2;
        int y = (screenHeight - cardHeight) / 2 - 36;
        centerCard.drawFront(g2, x, y, cardWidth, cardHeight);
    }

    private void drawPlayerHand(Graphics2D g2) {
        if (playerHand == null || playerHand.isEmpty()) {
            return;
        }

        double fanRadius = cardHeight + 95.0;
        double pivotX = screenWidth / 2.0;
        double pivotY = screenHeight + 220.0;
        double totalSpread = playerHand.size() == 1 ? 0 : HAND_FAN_SPREAD_DEGREES;
        double angleStep = playerHand.size() == 1 ? 0 : totalSpread / (playerHand.size() - 1);
        double startAngle = -totalSpread / 2.0;

        for (int i = 0; i < playerHand.size(); i++) {
            double angleDegrees = startAngle + (angleStep * i);
            double angleRadians = Math.toRadians(angleDegrees);

            double cardCenterX = pivotX + (Math.sin(angleRadians) * fanRadius);
            double cardTopY = pivotY - (Math.cos(angleRadians) * fanRadius) - cardHeight;
            int x = (int) Math.round(cardCenterX - (cardWidth / 2.0));
            int y = (int) Math.round(cardTopY);

            Graphics2D cardGraphics = (Graphics2D) g2.create();
            cardGraphics.rotate(angleRadians, x + (cardWidth / 2.0), y + (cardHeight * 0.92));
            playerHand.get(i).drawFront(cardGraphics, x, y, cardWidth, cardHeight);
            cardGraphics.dispose();
        }
    }

    private void drawDrawPile(Graphics2D g2) {
        if (drawPile == null || drawPile.isEmpty()) {
            return;
        }

        int visibleCards = Math.min(drawPile.size(), MAX_VISIBLE_STACK);
        int baseX = screenWidth - cardWidth - TABLE_MARGIN;
        int baseY = screenHeight - cardHeight - TABLE_MARGIN;

        for (int i = visibleCards - 1; i >= 0; i--) {
            int x = baseX - (i * STACK_OFFSET);
            int y = baseY - (i * STACK_OFFSET);
            Card.drawBackImage(g2, x, y, cardWidth, cardHeight);
        }
    }
}

package main;

import javax.swing.*;
import java.awt.*;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.awt.geom.AffineTransform;
import java.util.ArrayList;
import java.util.List;

public class GamePanel extends JPanel implements Runnable {
    //    Screen settings
    final int originalTilesSize = 64; // 16x16 tile
    final int scale = 2;

    public int tileSize = originalTilesSize * scale; // 48x48 tile
    final int maxScreenCol = 16;
    final int maxScreenRow = 12;
    final int screenWidth = (tileSize * maxScreenCol) / 2; // 768 pixels
    final int screenHeight = (tileSize * maxScreenRow) / 2; // 576 pixels

    //    Game's frame rate
    int FPS = 60;

    Thread gameThread;
    private static final int TABLE_MARGIN = 24;
    private static final int STACK_OFFSET = 4;
    private static final int MAX_VISIBLE_STACK = 6;
    private static final double HAND_FAN_SPREAD_DEGREES = 36.0;
    private static final String[] SUIT_OPTIONS = {"Basto", "Copa", "Espada", "Oro"};
    private final int cardWidth = tileSize - 24;
    private final int cardHeight = (int) Math.round(cardWidth * 1.45);
    private final Font hudFont = new Font("SansSerif", Font.BOLD, 16);
    private final Font smallHudFont = new Font("SansSerif", Font.PLAIN, 14);

    private final CopasGameState gameState;

    public GamePanel() {
        this.setPreferredSize(new Dimension(screenWidth, screenHeight));
        this.setBackground(new Color(16, 94, 58));
        this.setDoubleBuffered(true);
        this.gameState = new CopasGameState();
        this.addMouseListener(new TableMouseHandler());
    }

    public void startGameThread() {
        gameThread = new Thread(this);
        gameThread.start();
    }

    public void run() {
        double drawInterval = 1000000000.0 / FPS;
        double delta = 0;
        long lastTime = System.nanoTime();
        long currentTime;

        while (gameThread != null) {
            currentTime = System.nanoTime();

            delta += (currentTime - lastTime) / drawInterval;
            lastTime = currentTime;

            if (delta >= 1) {
                update();
                repaint();
                delta--;
            }

        }
    }

    //    Methode to update the frame
    public void update() {
        // Table is static for now.
    }

    //    Methode to draw
    public void paintComponent(Graphics g) {
        super.paintComponent(g);
        Graphics2D g2 = (Graphics2D) g;
        g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g2.setRenderingHint(RenderingHints.KEY_RENDERING, RenderingHints.VALUE_RENDER_QUALITY);

        drawCenterCard(g2);
        drawPlayerHand(g2);
        drawDrawPile(g2);
        drawHud(g2);

        g2.dispose();
    }

    private void drawCenterCard(Graphics2D g2) {
        int x = (screenWidth - cardWidth) / 2;
        int y = (screenHeight - cardHeight) / 2 - 36;
        gameState.getTopCard().drawFront(g2, x, y, cardWidth, cardHeight);

        g2.setFont(smallHudFont);
        g2.setColor(Color.WHITE);
        g2.drawString("Active suit: " + gameState.getActiveSuit(), x - 8, y - 12);
        g2.drawString("Top card: " + gameState.getTopCard().getDisplayName(), x - 8, y + cardHeight + 18);
    }

    private void drawPlayerHand(Graphics2D g2) {
        List<CardPlacement> placements = getPlayerHandPlacements();
        if (placements.isEmpty()) {
            return;
        }

        for (CardPlacement placement : placements) {
            Graphics2D cardGraphics = (Graphics2D) g2.create();
            cardGraphics.rotate(placement.angleRadians(), placement.rotationPivotX(), placement.rotationPivotY());
            placement.card().drawFront(cardGraphics, placement.x(), placement.y(), cardWidth, cardHeight);

            if (gameState.isHumanTurn() && gameState.isHumanCardPlayable(placement.handIndex())) {
                cardGraphics.setColor(new Color(255, 255, 255, 170));
                cardGraphics.setStroke(new BasicStroke(3f));
                cardGraphics.drawRoundRect(placement.x(), placement.y(), cardWidth, cardHeight, 16, 16);
            }

            cardGraphics.dispose();
        }
    }

    private void drawDrawPile(Graphics2D g2) {
        if (gameState.hasAvailableDrawPile()) {
            int visibleCards = Math.max(1, Math.min(gameState.getDrawPileSize(), MAX_VISIBLE_STACK));
            int baseX = screenWidth - cardWidth - TABLE_MARGIN;
            int baseY = screenHeight - cardHeight - TABLE_MARGIN;

            for (int i = visibleCards - 1; i >= 0; i--) {
                int x = baseX - (i * STACK_OFFSET);
                int y = baseY - (i * STACK_OFFSET);
                Card.drawBackImage(g2, x, y, cardWidth, cardHeight);
            }

            g2.setFont(smallHudFont);
            g2.setColor(Color.WHITE);
            g2.drawString("Draw pile: " + gameState.getDrawPileSize(), baseX - 18, baseY - 10);
            if (gameState.canHumanDraw()) {
                g2.drawString("Click to draw", baseX - 14, baseY + cardHeight + 18);
            }
        }
    }

    private void drawHud(Graphics2D g2) {
        g2.setFont(hudFont);
        g2.setColor(Color.WHITE);
        g2.drawString("Current turn: " + gameState.getPlayerName(gameState.getCurrentPlayerIndex()), TABLE_MARGIN, 28);

        g2.setFont(smallHudFont);
        drawWrappedStatus(g2, gameState.getStatusMessage(), TABLE_MARGIN, 54, screenWidth - (TABLE_MARGIN * 2), 18);

        int opponentsX = TABLE_MARGIN;
        int opponentsY = 120;
        for (int playerIndex = 1; playerIndex < 4; playerIndex++) {
            String label = gameState.getPlayerName(playerIndex) + ": "
                    + gameState.getPlayerCardCount(playerIndex)
                    + (gameState.isPlayerFinished(playerIndex) ? " (finished)" : " cards");
            g2.drawString(label, opponentsX, opponentsY + ((playerIndex - 1) * 20));
        }

        String humanLabel = "You: " + gameState.getPlayerCardCount(0)
                + (gameState.isPlayerFinished(0) ? " (finished)" : " cards");
        g2.drawString(humanLabel, TABLE_MARGIN, screenHeight - 16);
    }

    private void drawWrappedStatus(Graphics2D g2, String text, int x, int y, int maxWidth, int lineHeight) {
        FontMetrics metrics = g2.getFontMetrics();
        String[] words = text.split(" ");
        StringBuilder line = new StringBuilder();
        int lineY = y;

        for (String word : words) {
            String candidate = line.isEmpty() ? word : line + " " + word;
            if (metrics.stringWidth(candidate) > maxWidth && !line.isEmpty()) {
                g2.drawString(line.toString(), x, lineY);
                line = new StringBuilder(word);
                lineY += lineHeight;
            } else {
                line = new StringBuilder(candidate);
            }
        }

        if (!line.isEmpty()) {
            g2.drawString(line.toString(), x, lineY);
        }
    }

    private List<CardPlacement> getPlayerHandPlacements() {
        List<Card> playerHand = gameState.getHumanHand();
        List<CardPlacement> placements = new ArrayList<>();
        if (playerHand.isEmpty()) {
            return placements;
        }

        double fanRadius = cardHeight + 95.0;
        double pivotX = screenWidth / 2.0;
        double pivotY = screenHeight + 220.0;
        double totalSpread = playerHand.size() == 1 ? 0 : HAND_FAN_SPREAD_DEGREES;
        double angleStep = playerHand.size() == 1 ? 0 : totalSpread / (playerHand.size() - 1);
        double startAngle = -totalSpread / 2.0;

        for (int i = 0; i < playerHand.size(); i++) {
            double angleDegrees = startAngle + (angleStep * i);
            double angleRadians = Math.toRadians(angleDegrees);
            double cardCenterX = pivotX + (Math.sin(angleRadians) * fanRadius);
            double cardTopY = pivotY - (Math.cos(angleRadians) * fanRadius) - cardHeight;
            int x = (int) Math.round(cardCenterX - (cardWidth / 2.0));
            int y = (int) Math.round(cardTopY);
            double pivotRotationX = x + (cardWidth / 2.0);
            double pivotRotationY = y + (cardHeight * 0.92);
            Shape hitShape = AffineTransform.getRotateInstance(angleRadians, pivotRotationX, pivotRotationY)
                    .createTransformedShape(new Rectangle(x, y, cardWidth, cardHeight));

            placements.add(new CardPlacement(i, playerHand.get(i), x, y, angleRadians, pivotRotationX, pivotRotationY, hitShape));
        }

        return placements;
    }

    private Rectangle getDrawPileBounds() {
        if (gameState.hasAvailableDrawPile()) {
            int visibleCards = Math.max(1, Math.min(gameState.getDrawPileSize(), MAX_VISIBLE_STACK));

            int baseX = screenWidth - cardWidth - TABLE_MARGIN;
            int baseY = screenHeight - cardHeight - TABLE_MARGIN;
            int x = baseX - ((visibleCards - 1) * STACK_OFFSET);
            int y = baseY - ((visibleCards - 1) * STACK_OFFSET);
            int width = cardWidth + ((visibleCards - 1) * STACK_OFFSET);
            int height = cardHeight + ((visibleCards - 1) * STACK_OFFSET);
            return new Rectangle(x, y, width, height);
        }

        return new Rectangle();
    }

    private void handleMouseClick(Point point) {
        if (gameState.isRoundOver()) {
            return;
        }

        List<CardPlacement> placements = getPlayerHandPlacements();
        for (int placementIndex = placements.size() - 1; placementIndex >= 0; placementIndex--) {
            CardPlacement placement = placements.get(placementIndex);
            if (placement.hitShape().contains(point)) {
                String chosenSuit = placement.card().isSuitChange() ? requestSuitChoice() : null;
                if (placement.card().isSuitChange() && chosenSuit == null) {
                    return;
                }

                boolean cardPlayed = gameState.playHumanCard(placement.handIndex(), chosenSuit);
                if (!cardPlayed) {
                    Toolkit.getDefaultToolkit().beep();
                }
                repaint();
                return;
            }
        }

        if (getDrawPileBounds().contains(point)) {
            gameState.drawForHuman();
            repaint();
        }
    }

    private String requestSuitChoice() {
        Object selection = JOptionPane.showInputDialog(
                this,
                "Choose the next suit:",
                "Change Suit",
                JOptionPane.PLAIN_MESSAGE,
                null,
                SUIT_OPTIONS,
                gameState.getActiveSuit()
        );

        return selection instanceof String ? (String) selection : null;
    }

    private record CardPlacement(
            int handIndex,
            Card card,
            int x,
            int y,
            double angleRadians,
            double rotationPivotX,
            double rotationPivotY,
            Shape hitShape
    ) {
    }

    private class TableMouseHandler extends MouseAdapter {
        @Override
        public void mouseClicked(MouseEvent e) {
            handleMouseClick(e.getPoint());
        }
    }
}
